local FEEDBACK_COOLDOWN, lastFeedback = 20, 0
local ERRMAP = {
    empty = "Pesan kosong.", no_links = "Tautan tidak diperbolehkan.",
    too_long = "Pesan terlalu panjang (maksimal 500 karakter).", rate_limited = "Anda telah mencapai batas 3 pesan. Silakan coba lagi nanti.",
    busy = "Server sedang sibuk. Silakan coba lagi.", banned = "Anda tidak diperbolehkan mengirim masukan.",
    discord_error = "Pengiriman gagal. Silakan coba lagi.", network = "Kesalahan jaringan.",
    no_request = "Executor Anda tidak dapat mengirim permintaan.", bad_response = "Server memberikan respons yang tidak terduga.",
    unreachable = "Executor Anda tidak dapat menjangkau server (kesalahan TLS). Silakan coba executor lain.",
}
local FG = Tabs.Suggest:AddLeftGroupbox("Saran / Bantuan", "message-square")
FG:AddDropdown("FeedbackType", {Text = "Tipe", Values = {"Suggestion", "Bug", "Help"}, Default = "Suggestion", Callback = function() end})
FG:AddInput("FeedbackMsg", {Default = "", Numeric = false, Finished = false, ClearTextOnFocus = false, Text = "Pesan", Placeholder = "Ketik pesan Anda (maksimal 500 karakter, tanpa tautan)"})
local fbStatus = FG:AddLabel("", true)
FG:AddButton({
    Text = "📨 Send",
    Func = function()
        local now = tick()
        if now - lastFeedback < FEEDBACK_COOLDOWN then
            safeSet(fbStatus, string.format("Harap tunggu %d detik sebelum mengirim lagi.", math.ceil(FEEDBACK_COOLDOWN - (now - lastFeedback))))
            return
        end
        local ftype = tostring((Options.FeedbackType and Options.FeedbackType.Value) or "Suggestion"):lower()
        local msg   = M.trim((Options.FeedbackMsg and Options.FeedbackMsg.Value) or "")
        if msg == "" then safeSet(fbStatus, "Pesan kosong."); return end
        if #msg > 500 then safeSet(fbStatus, "Pesan terlalu panjang (maksimal 500 karakter)."); return end
        local low = msg:lower()
        if low:find("http", 1, true) or low:find("discord.gg", 1, true) or low:find("www.", 1, true) or low:find(".gg/", 1, true) then
            safeSet(fbStatus, "Tautan tidak diperbolehkan."); return
        end
        safeSet(fbStatus, "Mengirim...")
        task.spawn(function()
            local sok, err = M.sendFeedback(ftype, msg, (preCheck and preCheck.session_token) or "")
            if sok then
                lastFeedback = tick()
                safeSet(fbStatus, "✅ Terkirim. Terima kasih!")
                pcall(function() Options.FeedbackMsg:SetValue("") end)
                Library:Notify({Title = "COMBOWICK", Description = "Masukan Anda telah terkirim. Terima kasih!", Time = 3})
            else
                safeSet(fbStatus, ERRMAP[err] or ("Gagal mengirim: " .. tostring(err)))
            end
        end)
    end,
})
FG:AddLabel("Maksimal 3 pesan per jam. Tanpa tautan atau mention.", true)

