task.spawn(function()
    safeSet(statusLabel, "Mengautentikasi...")

    local result = M.withRetry(M.checkSession, M.hwid)

    if result == nil then
        safeSet(statusLabel, "Status: Gagal")
        Library:Notify({Title="COMBOWICK", Description="Pemeriksaan sesi gagal.", Time=5})

    elseif result.status == "allowed" or result.status == "session_active" then
        if result.disabled then
            safeSet(statusLabel, "⛔ Game Dinonaktifkan")
            safeSet(hintLabel, "Versi gratis tidak tersedia di sini. Dapatkan key.")
            Library:Notify({Title="COMBOWICK", Description="Versi gratis dinonaktifkan untuk game ini. Silakan gunakan key.", Time=6})
            return
        end
        local token = result.session_token
        if type(token) ~= "string" or #token < 20 then
            safeSet(statusLabel, "Status: Gagal")
        else
            safeSet(statusLabel, "Status: Terautentikasi")
            Library:Notify({Title="COMBOWICK", Description="Anda telah terautentikasi.", Time=3})
            _G.COMBOWICK_FREE   = true
            _G.COMBOWICK_ACTIVE = true
            local remaining = tonumber(result.remaining) or 0
            task.spawn(function()
                while remaining > 0 do
                    local fmt = M.formatTime(remaining)
                    safeSet(timerLabel, string.format("Sisa waktu: %s", fmt))
                    safeSet(lSession, string.format("Waktu sesi: %s", fmt))
                    task.wait(1); remaining = remaining - 1
                end
                safeSet(timerLabel, "Sesi telah berakhir.")
                safeSet(lSession, "Waktu sesi: berakhir")
                _G.COMBOWICK_ACTIVE = false
                pcall(function() Library:Unload() end)
                task.wait(0.5)
                M.reloadExist()
            end)
            local scriptUrl = M.getScriptForGame(token)
            if M.loadFreeScript(scriptUrl, token) then task.wait(2); pcall(function() Library:Unload() end) end
        end

    elseif result.status == "cooldown" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Sedang Jeda")
        safeSet(hintLabel, "Dapatkan key 11 jam, atau tunggu jeda selesai.")
        Library:Notify({Title="COMBOWICK", Description="Anda sedang dalam jeda. Dapatkan key untuk melewati masa tunggu.", Time=6})
        task.spawn(function()
            while remaining > 0 do
                local fmt = M.formatTime(remaining)
                safeSet(timerLabel, string.format("Jeda: %s", fmt))
                safeSet(lCooldown, string.format("Jeda: %s", fmt))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Jeda telah selesai.")
            safeSet(lCooldown, "Jeda: selesai")
            safeSet(hintLabel, "")
            Library:Notify({Title="COMBOWICK", Description="Jeda telah selesai. Memuat ulang...", Time=3})
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "throttled" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Terlalu Banyak Permintaan")
        safeSet(hintLabel, "Terlalu banyak permintaan. Harap tunggu.")
        Library:Notify({Title="COMBOWICK", Description="Terlalu banyak permintaan. Harap tunggu sebentar.", Time=5})
        task.spawn(function()
            while remaining > 0 do
                safeSet(timerLabel, string.format("Coba lagi dalam %s", M.formatTime(remaining)))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Memuat ulang...")
            safeSet(hintLabel, "")
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "disabled" then
        safeSet(statusLabel, "Layanan Dijeda")
        safeSet(hintLabel, "COMBOWICK sedang offline sementara.")
        Library:Notify({Title="COMBOWICK", Description="Layanan saat ini dinonaktifkan. Silakan coba lagi nanti.", Time=6})

    elseif result.status == "banned" then
        safeSet(statusLabel, "Diblokir")
        Library:Notify({Title="COMBOWICK", Description="Anda diblokir.", Time=5})

    elseif result.status == "game_not_allowed" then
        safeSet(statusLabel, "🚫 Game Tidak Didukung")
        safeSet(hintLabel, "Game ini belum didukung. Key premium tetap berfungsi jika script tersedia.")
        Library:Notify({Title="COMBOWICK", Description="Game ini belum didukung.", Time=6})

    else
        safeSet(statusLabel, "Kesalahan")
        safeSet(hintLabel, "Tidak dapat menjangkau server. Silakan jalankan script lagi.")
        Library:Notify({Title="COMBOWICK", Description=tostring(result.message or "Terjadi kesalahan yang tidak diketahui."), Time=5})
    end
end)

